import { corsHeaders } from "../_shared/cors.ts";
import { requireZernioAuth } from "../_shared/zernioAuth.ts";
import { zernioFetch } from "../_shared/zernioClient.ts";
import { resolveZernioProfileId } from "../_shared/zernioProfiles.ts";
import { canAccessScope, canConnectOrg, type ZernioScope } from "../_shared/zernioRbac.ts";

function jsonResponse(status: number, body: unknown) {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

type ConnectBody = {
  scope?: ZernioScope;
  platform?: string;
  redirect_url?: string;
};

export default async function handler(req: Request): Promise<Response> {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  if (req.method !== "POST") return jsonResponse(405, { ok: false, error: "Method not allowed" });

  const auth = await requireZernioAuth(req);
  if (auth instanceof Response) return auth;

  let body: ConnectBody;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { ok: false, error: "JSON inválido" });
  }

  const scope = body.scope === "org" ? "org" : body.scope === "personal" ? "personal" : null;
  const platform = (body.platform ?? "").trim().toLowerCase();
  if (!scope) return jsonResponse(400, { ok: false, error: "scope debe ser org o personal" });
  if (!platform) return jsonResponse(400, { ok: false, error: "platform es requerido" });

  if (scope === "org" && !canConnectOrg(auth.role)) {
    return jsonResponse(403, { ok: false, error: "No tienes permiso para conectar cuentas de la automotora" });
  }
  if (!canAccessScope(scope, auth.role)) {
    return jsonResponse(403, { ok: false, error: "Sin permiso para este ámbito" });
  }

  try {
    const { data: tenant } = await auth.admin
      .from("tenants")
      .select("name")
      .eq("id", auth.tenantId)
      .maybeSingle();

    const { data: userRow } = await auth.admin
      .from("users")
      .select("full_name, email")
      .eq("id", auth.userId)
      .maybeSingle();

    const profileId = await resolveZernioProfileId(
      auth.admin,
      auth.tenantId,
      auth.userId,
      scope,
      tenant?.name ?? "Automotora",
      userRow?.full_name ?? userRow?.email ?? "Usuario",
    );

    const redirectUrl = (body.redirect_url ?? "").trim();
    if (!redirectUrl) {
      return jsonResponse(400, { ok: false, error: "redirect_url es requerido" });
    }
    try {
      new URL(redirectUrl);
    } catch {
      return jsonResponse(400, { ok: false, error: "redirect_url inválido" });
    }

    const connect = await zernioFetch<{ authUrl?: string; auth_url?: string }>(
      `/connect/${encodeURIComponent(platform)}?profileId=${encodeURIComponent(profileId)}&redirect_url=${encodeURIComponent(redirectUrl)}`,
    );

    const authUrl = connect.authUrl ?? connect.auth_url;
    if (!authUrl) {
      return jsonResponse(502, { ok: false, error: "Zernio no devolvió URL de conexión" });
    }

    return jsonResponse(200, { ok: true, authUrl, scope, platform });
  } catch (e) {
    return jsonResponse(500, { ok: false, error: (e as Error).message });
  }
}

// CORS helper para Edge Functions.
//
// En producción, setear el secret `ALLOWED_ORIGINS` en Supabase con la lista
// de orígenes separados por coma (ej: "https://app.skalemotors.cl,https://skalemotors.cl").
// Si no está seteado, mantiene el comportamiento legacy (wildcard).
//
// Uso recomendado en handlers:
//   const cors = getCorsHeaders(req);
//   ...new Response(..., { headers: { ...cors } });
//
// Compatibilidad: corsHeaders (constante con `*`) se mantiene para no romper
// las funciones existentes hasta que se migren una a una.

const ALLOWED_HEADERS =
  "authorization, x-client-info, apikey, content-type, x-api-key, x-webhook-token, x-signature, x-hub-signature-256, idempotency-key";
const ALLOWED_METHODS = "GET,POST,OPTIONS";
const MAX_AGE = "86400";

function getAllowedOrigins(): string[] | null {
  const raw = Deno.env.get("ALLOWED_ORIGINS");
  if (!raw) return null;
  return raw.split(",").map((s) => s.trim()).filter(Boolean);
}

export function getCorsHeaders(req: Request): Record<string, string> {
  const origin = req.headers.get("origin");
  const allowed = getAllowedOrigins();
  let allowOrigin = "*";
  if (allowed && allowed.length > 0) {
    allowOrigin = origin && allowed.includes(origin) ? origin : allowed[0];
  }
  return {
    "Access-Control-Allow-Origin": allowOrigin,
    "Vary": "Origin",
    "Access-Control-Allow-Headers": ALLOWED_HEADERS,
    "Access-Control-Allow-Methods": ALLOWED_METHODS,
    "Access-Control-Max-Age": MAX_AGE,
  };
}

// Constante compartida. Si `ALLOWED_ORIGINS` está seteado en Supabase Secrets,
// usa el primer origen permitido (lockdown CORS). Si no, fallback a `*` (legacy).
// Para validación per-request real (multi-origen con echo del origen del request),
// usar getCorsHeaders(req).
function resolveDefaultAllowOrigin(): string {
  const allowed = getAllowedOrigins();
  if (allowed && allowed.length > 0) return allowed[0];
  return "*";
}

export const corsHeaders = {
  "Access-Control-Allow-Origin": resolveDefaultAllowOrigin(),
  "Vary": "Origin",
  "Access-Control-Allow-Headers": ALLOWED_HEADERS,
  "Access-Control-Allow-Methods": ALLOWED_METHODS,
  "Access-Control-Max-Age": MAX_AGE,
};

import { createClient, type SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";

export type ZernioAuthContext = {
  userId: string;
  tenantId: string;
  role: string;
  branchId: string | null;
  userClient: SupabaseClient;
  admin: SupabaseClient;
};

function getEnv(name: string): string | null {
  return Deno.env.get(name) ?? null;
}

export async function requireZernioAuth(req: Request): Promise<ZernioAuthContext | Response> {
  const authHeader = req.headers.get("authorization") || "";
  if (!authHeader.toLowerCase().startsWith("bearer ")) {
    return new Response(JSON.stringify({ ok: false, error: "Missing auth" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    });
  }

  const supabaseUrl = getEnv("SUPABASE_URL") ?? getEnv("PROJECT_URL");
  const anonKey = getEnv("SUPABASE_ANON_KEY");
  const serviceRoleKey = getEnv("SUPABASE_SERVICE_ROLE_KEY") ?? getEnv("SERVICE_ROLE_KEY");
  if (!supabaseUrl || !anonKey || !serviceRoleKey) {
    return new Response(JSON.stringify({ ok: false, error: "Missing Supabase env vars" }), {
      status: 500,
      headers: { "Content-Type": "application/json" },
    });
  }

  const userClient = createClient(supabaseUrl, anonKey, {
    global: { headers: { Authorization: authHeader } },
  });
  const { data: userData, error: userErr } = await userClient.auth.getUser();
  if (userErr || !userData?.user) {
    return new Response(JSON.stringify({ ok: false, error: "Invalid auth" }), {
      status: 401,
      headers: { "Content-Type": "application/json" },
    });
  }

  const admin = createClient(supabaseUrl, serviceRoleKey, { auth: { persistSession: false } });
  const { data: profile, error: profileErr } = await admin
    .from("users")
    .select("id, tenant_id, branch_id, role")
    .eq("id", userData.user.id)
    .maybeSingle();

  if (profileErr || !profile?.tenant_id) {
    return new Response(JSON.stringify({ ok: false, error: "Perfil de usuario no encontrado" }), {
      status: 403,
      headers: { "Content-Type": "application/json" },
    });
  }

  return {
    userId: userData.user.id,
    tenantId: profile.tenant_id,
    role: profile.role ?? "vendedor",
    branchId: profile.branch_id ?? null,
    userClient,
    admin,
  };
}

const ZERNIO_API_BASE = "https://zernio.com/api/v1";

export async function zernioFetch<T>(
  path: string,
  init?: { method?: string; body?: unknown },
): Promise<T> {
  const apiKey = Deno.env.get("ZERNIO_API_KEY");
  if (!apiKey) {
    throw new Error("ZERNIO_API_KEY no configurada en Supabase Secrets");
  }

  const res = await fetch(`${ZERNIO_API_BASE}${path}`, {
    method: init?.method ?? "GET",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: init?.body !== undefined ? JSON.stringify(init.body) : undefined,
  });

  const json = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg =
      (json as { message?: string }).message ??
      (json as { error?: string }).error ??
      res.statusText;
    throw new Error(typeof msg === "string" ? msg : "Error en Zernio API");
  }
  return json as T;
}

import type { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";
import { zernioFetch } from "./zernioClient.ts";

type ZernioProfileResponse = {
  profile?: { _id?: string };
  _id?: string;
};

export async function getOrCreateOrgZernioProfile(
  admin: SupabaseClient,
  tenantId: string,
  displayName: string,
): Promise<string> {
  const { data: existing } = await admin
    .from("zernio_org_profiles")
    .select("zernio_profile_id")
    .eq("tenant_id", tenantId)
    .maybeSingle();

  if (existing?.zernio_profile_id) {
    return existing.zernio_profile_id;
  }

  const created = await zernioFetch<ZernioProfileResponse>("/profiles", {
    method: "POST",
    body: {
      name: displayName.slice(0, 120) || `Automotora ${tenantId.slice(0, 8)}`,
      description: "Perfil organizacional Skale Motors",
    },
  });

  const zernioProfileId = created.profile?._id ?? created._id;
  if (!zernioProfileId) {
    throw new Error("Zernio no devolvió profile id");
  }

  const { error } = await admin.from("zernio_org_profiles").upsert(
    {
      tenant_id: tenantId,
      zernio_profile_id: zernioProfileId,
      updated_at: new Date().toISOString(),
    },
    { onConflict: "tenant_id" },
  );
  if (error) throw new Error(error.message);

  return zernioProfileId;
}

export async function getOrCreateUserZernioProfile(
  admin: SupabaseClient,
  tenantId: string,
  userId: string,
  displayName: string,
): Promise<string> {
  const { data: existing } = await admin
    .from("zernio_user_profiles")
    .select("zernio_profile_id")
    .eq("user_id", userId)
    .maybeSingle();

  if (existing?.zernio_profile_id) {
    return existing.zernio_profile_id;
  }

  const created = await zernioFetch<ZernioProfileResponse>("/profiles", {
    method: "POST",
    body: {
      name: displayName.slice(0, 120) || `Usuario ${userId.slice(0, 8)}`,
      description: "Perfil personal Skale Motors",
    },
  });

  const zernioProfileId = created.profile?._id ?? created._id;
  if (!zernioProfileId) {
    throw new Error("Zernio no devolvió profile id");
  }

  const { error } = await admin.from("zernio_user_profiles").upsert(
    {
      tenant_id: tenantId,
      user_id: userId,
      zernio_profile_id: zernioProfileId,
      updated_at: new Date().toISOString(),
    },
    { onConflict: "user_id" },
  );
  if (error) throw new Error(error.message);

  return zernioProfileId;
}

export async function resolveZernioProfileId(
  admin: SupabaseClient,
  tenantId: string,
  userId: string,
  scope: "org" | "personal",
  tenantName: string,
  userName: string,
): Promise<string> {
  if (scope === "org") {
    return getOrCreateOrgZernioProfile(admin, tenantId, tenantName);
  }
  return getOrCreateUserZernioProfile(admin, tenantId, userId, userName);
}

export type ZernioScope = "org" | "personal";

const ORG_CONNECT_ROLES = new Set(["admin", "gerente", "jefe_jefe"]);
const ORG_PUBLISH_ROLES = new Set(["admin", "gerente", "jefe_jefe", "jefe_sucursal"]);

export function canConnectOrg(role: string | null | undefined): boolean {
  return !!role && ORG_CONNECT_ROLES.has(role);
}

export function canPublishOrg(role: string | null | undefined): boolean {
  return !!role && ORG_PUBLISH_ROLES.has(role);
}

export function canAccessScope(scope: ZernioScope, role: string | null | undefined): boolean {
  if (scope === "personal") return true;
  return canViewOrg(scope, role);
}

export function canViewOrg(_scope: ZernioScope, role: string | null | undefined): boolean {
  return canPublishOrg(role) || canConnectOrg(role);
}

export function canMutateOrgAccounts(role: string | null | undefined): boolean {
  return canConnectOrg(role);
}
